  const seasonDetails=[...panel.querySelectorAll('.series-season')];seasonDetails.forEach(details=>{const season=Number(details.dataset.season),summary=details.querySelector('summary'),label=document.createElement('label');label.className='detail-select season-select';label.innerHTML=`<input type="checkbox" aria-label="Select season ${season}">`;summary.prepend(label);label.addEventListener('click',event=>event.stopPropagation());label.querySelector('input').onchange=event=>{event.target.checked?selectedSeasons.add(season):selectedSeasons.delete(season);refresh();};details.querySelectorAll('.episode').forEach(row=>{const button=row.querySelector('.episode-monitor'),id=Number(button.dataset.id.replace('episode_','')),label=document.createElement('label');label.className='detail-select episode-select';label.innerHTML=`<input type="checkbox" aria-label="Select episode ${id}">`;row.prepend(label);label.querySelector('input').onchange=event=>{event.target.checked?selectedEpisodes.add(id):selectedEpisodes.delete(id);refresh();};});});
