  function refresh(){const total=selectedSeasons.size+selectedEpisodes.size;count.textContent=`${total} selected`;buttons.forEach(button=>button.disabled=!total);}
  async function setMonitoring(monitored){buttons.forEach(button=>button.disabled=true);let completed=0,failed=0;try{if(selectedSeasons.size){const{result:series}=await api(`/api/manage/tv/library/${engineId}`);for(const season of series.seasons||[])if(selectedSeasons.has(Number(season.seasonNumber)))season.monitored=monitored;await api(`/api/manage/tv/library/${engineId}`,{method:'PUT',body:JSON.stringify(series)});completed+=selectedSeasons.size;}for(const id of selectedEpisodes){try{const{result:episode}=await api(`/api/manage/tv/episodes/${id}`);episode.monitored=monitored;await api(`/api/manage/tv/episodes/${id}`,{method:'PUT',body:JSON.stringify(episode)});completed++;}catch{failed++;}}notify(`${completed} television item${completed===1?'':'s'} ${monitored?'monitored':'unmonitored'}${failed?` · ${failed} failed`:''}.`,failed?'error':'success');await showDetail('series',item.id);}catch(error){notify(error.message,'error');refresh();}}
  bar.querySelector('.bulk-monitor').onclick=()=>setMonitoring(true);bar.querySelector('.bulk-unmonitor').onclick=()=>setMonitoring(false);bar.querySelector('.bulk-search').onclick=async()=>{buttons.forEach(button=>button.disabled=true);let queued=0,failed=0;for(const seasonNumber of selectedSeasons){try{await api('/api/manage/tv/commands',{method:'POST',body:JSON.stringify({name:'SeasonSearch',seriesId:Number(engineId),seasonNumber})});queued++;}catch{failed++;}}if(selectedEpisodes.size)try{await api('/api/manage/tv/commands',{method:'POST',body:JSON.stringify({name:'EpisodeSearch',episodeIds:[...selectedEpisodes]})});queued+=selectedEpisodes.size;}catch{failed+=selectedEpisodes.size;}notify(`${queued} search${queued===1?'':'es'} queued${failed?` · ${failed} failed`:''}.`,failed?'error':'success');refresh();};bar.querySelector('.bulk-clear').onclick=()=>{selectedSeasons.clear();selectedEpisodes.clear();panel.querySelectorAll('.detail-select input').forEach(input=>input.checked=false);refresh();};refresh();
