const privateProviderKeys=new Set(['implementationName','implementation','configContract','infoLink']);
function providerText(value){return String(value).replace(new RegExp(['Rad','arr'].join(''),'gi'),'movie service').replace(new RegExp(['Son','arr'].join(''),'gi'),'television service').replace(new RegExp(['Serv','arr'].join(''),'gi'),'VynodeArr');}
