function mediaSettingField(field){const value=field.value,options=field.key==='colonReplacementFormat'&&typeof value==='number'?[[0,'Delete'],[1,'Dash'],[2,'Space + dash'],[3,'Space + dash + space'],[4,'Smart replacement'],[5,'Custom replacement']]:mediaSettingOptions[field.key],help=mediaSettingHelp[field.key]||'',path=esc(field.path),label=esc(mediaSettingLabel(field.key));if(typeof value==='boolean')return`<label class="config-switch"><span><strong>${label}</strong>${help?`<small>${esc(help)}</small>`:''}</span><input data-config-path="${path}" data-config-type="boolean" type="checkbox"${value?' checked':''}></label>`;if(options){const choices=[...options];if(!choices.some(([option])=>String(option)===String(value)))choices.unshift([value,mediaSettingLabel(value)]);return`<label>${label}${help?`<small>${esc(help)}</small>`:''}<select data-config-path="${path}" data-config-type="${typeof value}">${choices.map(([option,text])=>`<option value="${esc(option)}"${String(option)===String(value)?' selected':''}>${esc(text)}</option>`).join('')}</select></label>`;}const type=typeof value==='number'?'number':'text',serialized=Array.isArray(value)?value.join(', '):value??'',format=/Format$/.test(field.key);return`<label>${label}${help?`<small>${esc(help)}</small>`:''}${format?`<textarea data-config-path="${path}" data-config-type="${Array.isArray(value)?'array':typeof value}" rows="3">${esc(serialized)}</textarea>`:`<input data-config-path="${path}" data-config-type="${Array.isArray(value)?'array':type}" type="${type}" value="${esc(serialized)}">`}</label>`;}
