async function showProviders(kind){
  const indexer=kind==='indexers',title=indexer?'Indexers':'Download Clients',schema=indexer?'indexerSchemas':'downloadClientSchemas';
  content.innerHTML=`<div class="hero"><div><span class="eyebrow">SERVICE SETTINGS</span><h1>${title}</h1><p class="lede">${indexer?'Configure release sources and search behavior.':'Connect and configure applications that receive downloads.'}</p></div><button id="new-provider" class="primary">Add ${indexer?'indexer':'download client'}</button></div>${serviceTabs(indexer?'indexers':'download-clients')}<div class="management-toolbar"><label>Library<select id="provider-domain"><option value="movie">Movies</option><option value="tv">Television</option></select></label></div>${indexer?'':'<section id="failed-download-policy" class="panel skeleton">Loading failed-download policy…</section>'}<div class="profile-layout"><section id="provider-list" class="panel profile-list"></section><section id="provider-editor" class="panel"><div class="empty"><h2>Select a provider</h2></div></section></div><dialog id="provider-kind-dialog"></dialog>`;
  const domain=document.querySelector('#provider-domain'),list=document.querySelector('#provider-list'),editor=document.querySelector('#provider-editor');let records=[];
  async function loadPolicy(){if(indexer)return;const host=document.querySelector('#failed-download-policy');try{const{result}=await api(`/api/manage/${domain.value}/downloadClientSettings`);host.className='panel';host.innerHTML=`<form id="failed-download-form"><div class="panel-heading"><div><h2>Failed download handling</h2><p class="muted">Choose whether the engine should block a failed release and automatically grab another result.</p></div><button class="primary" type="submit">Save policy</button></div><div class="form-grid"><label class="check"><input name="enableCompletedDownloadHandling" type="checkbox"${result.enableCompletedDownloadHandling?' checked':''}> Process completed downloads</label><label class="check"><input name="autoRedownloadFailed" type="checkbox"${result.autoRedownloadFailed?' checked':''}> Automatically replace failed automatic/manual grabs</label><label class="check"><input name="autoRedownloadFailedFromInteractiveSearch" type="checkbox"${result.autoRedownloadFailedFromInteractiveSearch?' checked':''}> Automatically replace failed interactive grabs</label></div></form>`;host.querySelector('form').addEventListener('submit',async event=>{event.preventDefault();const target=event.currentTarget,payload={...result,enableCompletedDownloadHandling:target.elements.enableCompletedDownloadHandling.checked,autoRedownloadFailed:target.elements.autoRedownloadFailed.checked,autoRedownloadFailedFromInteractiveSearch:target.elements.autoRedownloadFailedFromInteractiveSearch.checked};try{await api(`/api/manage/${domain.value}/downloadClientSettings`,{method:'PUT',body:JSON.stringify(payload)});notify('Failed-download policy saved.');await loadPolicy();}catch(error){notify(error.message,'error');}});}catch(error){host.className='panel error-state';host.innerHTML=`<p>${esc(error.message)}</p>`;}}
  function control(field,i){const value=field.value??'',secret=['password','apiKey'].includes(field.privacy)||field.type==='password';if(['checkbox','boolean'].includes(field.type))return`<label class="check provider-field"><input data-field="${i}" type="checkbox"${value?' checked':''}> ${esc(field.label||field.name)}${field.advanced?' (Advanced)':''}</label>`;if(field.type==='select'&&field.selectOptions?.length){const multi=Array.isArray(value),selected=multi?value.map(String):[String(value)];return`<label class="provider-field">${esc(field.label||field.name)}${field.advanced?' <small>Advanced</small>':''}<select data-field="${i}"${multi?' multiple':''}>${field.selectOptions.map(option=>`<option value="${esc(option.value)}"${selected.includes(String(option.value))?' selected':''}>${esc(option.name)}${option.hint?` ${esc(option.hint)}`:''}</option>`).join('')}</select>${field.helpText?`<small>${esc(field.helpText)}</small>`:''}</label>`;}return`<label class="provider-field">${esc(field.label||field.name)}${field.advanced?' <small>Advanced</small>':''}<input data-field="${i}" type="${secret?'password':field.type==='number'?'number':'text'}" value="${esc(value==='********'?'':value)}"${field.isFloat?' step="any"':''}>${field.helpText?`<small>${esc(field.helpText)}</small>`:''}</label>`;}
  function edit(source,isNew=false){const item=structuredClone(source);editor.innerHTML=`<form id="provider-native-form"><div class="panel-heading"><h2>${isNew?'Add':`Edit ${esc(item.name)}`}</h2>${isNew?'':`<button class="danger delete-provider" type="button">Delete</button>`}</div><div class="form-grid"><label>Name<input name="name" value="${esc(item.name||item.implementationName||'')}" required></label><label>Priority<input name="priority" type="number" value="${item.priority??25}"></label><label class="check"><input name="enable" type="checkbox"${(item.enable??true)?' checked':''}> Enabled</label>${indexer?`<label class="check"><input name="enableRss" type="checkbox"${item.enableRss?' checked':''}> RSS</label><label class="check"><input name="enableAutomaticSearch" type="checkbox"${item.enableAutomaticSearch?' checked':''}> Automatic search</label><label class="check"><input name="enableInteractiveSearch" type="checkbox"${item.enableInteractiveSearch?' checked':''}> Interactive search</label>`:`<label class="check"><input name="removeCompletedDownloads" type="checkbox"${item.removeCompletedDownloads?' checked':''}> Remove completed</label><label class="check"><input name="removeFailedDownloads" type="checkbox"${item.removeFailedDownloads?' checked':''}> Remove failed</label>`}</div><h3>All provider options</h3><div class="provider-fields">${(item.fields||[]).map(control).join('')}</div><div class="form-actions"><button class="primary" type="submit">Save</button></div></form>`;const form=editor.querySelector('form');function payload(){const result=structuredClone(item);result.name=form.elements.name.value;result.priority=Number(form.elements.priority.value);result.enable=form.elements.enable.checked;for(const key of indexer?['enableRss','enableAutomaticSearch','enableInteractiveSearch']:['removeCompletedDownloads','removeFailedDownloads'])result[key]=form.elements[key].checked;result.fields=(result.fields||[]).map((field,i)=>{const input=form.querySelector(`[data-field="${i}"]`);let value;if(input.type==='checkbox')value=input.checked;else if(input.multiple)value=[...input.selectedOptions].map(option=>Number.isNaN(Number(option.value))?option.value:Number(option.value));else if(field.type==='number')value=input.value===''?null:Number(input.value);else value=input.value||field.value;return{...field,value};});return result;}form.addEventListener('submit',async event=>{event.preventDefault();try{await api(`/api/manage/${domain.value}/${kind}${isNew?'':`/${item.id}`}`,{method:isNew?'POST':'PUT',body:JSON.stringify(payload())});notify(`${indexer?'Indexer':'Download client'} saved.`);await load();}catch(error){notify(error.message,'error');}});if(!isNew)form.querySelector('.delete-provider').addEventListener('click',async()=>{if(!confirm(`Delete ${item.name}?`))return;try{await api(`/api/manage/${domain.value}/${kind}/${item.id}`,{method:'DELETE'});notify('Provider deleted.');await load();}catch(error){notify(error.message,'error');}});}
  async function add(){try{const{result:definitions}=await api(`/api/manage/${domain.value}/${schema}`),dialog=document.querySelector('#provider-kind-dialog');dialog.innerHTML=`<div class="provider-chooser"><div class="panel-heading"><h2>Choose a provider</h2><button class="secondary close-provider-kind">Cancel</button></div><label>Provider<select id="native-provider-kind">${definitions.map((definition,i)=>`<option value="${i}">${esc(definition.name||definition.implementationName||definition.implementation)}</option>`).join('')}</select></label><div class="form-actions"><button id="choose-provider-kind" class="primary">Configure</button></div></div>`;dialog.querySelector('.close-provider-kind').addEventListener('click',()=>dialog.close());dialog.querySelector('#choose-provider-kind').addEventListener('click',()=>{const chosen=definitions[Number(dialog.querySelector('select').value)];dialog.close();edit(chosen,true);});dialog.showModal();}catch(error){notify(error.message,'error');}}
  async function load(){list.innerHTML='<div class="skeleton">Loading…</div>';try{const{result}=await api(`/api/manage/${domain.value}/${kind}`);records=Array.isArray(result)?result:[];list.innerHTML=records.length?records.map((record,i)=>`<button class="profile-item" data-index="${i}"><strong>${esc(record.name||record.implementationName)}</strong><small>${esc(record.implementationName||record.implementation||record.protocol||'Provider')} · ${(record.enable??true)?'Enabled':'Disabled'}</small></button>`).join(''):`<div class="empty compact"><h2>No ${title.toLowerCase()}</h2><p>Use Add to configure one.</p></div>`;list.querySelectorAll('.profile-item').forEach(button=>button.addEventListener('click',()=>edit(records[Number(button.dataset.index)])));editor.innerHTML='<div class="empty"><h2>Select a provider</h2><p>Choose a configured provider or add a new one.</p></div>';}catch(error){list.innerHTML=`<div class="error-state"><p>${esc(error.message)}</p></div>`;}await loadPolicy();}
  domain.addEventListener('change',load);document.querySelector('#new-provider').addEventListener('click',add);await load();
}
async function showServiceSettings(section='root-folders'){if(state.user.role!=='administrator'){content.innerHTML='<div class="empty error-state"><h2>Administrator access required</h2></div>';return;}if(section==='media-management')return showMediaManagement();if(section==='profiles')return showProfiles();if(section==='indexers')return showProviders('indexers');if(section==='download-clients')return showProviders('downloadClients');return showRootFolders();}
function taskSections(items){return`<div class="system-domain-grid">${[['movie','Movies'],['tv','Television']].map(([domain,label])=>{const tasks=items.filter(item=>item.domain===domain);return`<section class="system-domain-section"><div class="panel-heading"><div><span class="eyebrow">${domain==='movie'?'MOVIE ENGINE':'TELEVISION ENGINE'}</span><h2>${label} tasks</h2></div><span class="badge">${tasks.length}</span></div>${tasks.map(item=>`<div class="data-row"><span><strong>${esc(item.name||item.taskName)}</strong><small>Next ${esc(when(item.nextExecution))}</small></span><button class="secondary run-task" data-domain="${item.domain}" data-name="${esc(item.taskName)}">Run now</button></div>`).join('')||'<p class="muted">No scheduled tasks reported.</p>'}</section>`;}).join('')}</div>`;}
function statusSections(values){return`<div class="system-domain-grid status-domain-grid">${values.map(value=>{const label=value.domain==='movie'?'Movies':'Television',disks=value.result||[],primary=disks.find(disk=>disk.path===(value.domain==='movie'?'/movies':'/tv'))||disks[0],free=Number(primary?.freeSpace||0),total=Number(primary?.totalSpace||0),used=Math.max(0,total-free),freePercent=total?Math.round(free/total*100):0,healthy=free>10737418240;return`<section class="system-domain-section status-domain-section"><div class="panel-heading"><div><span class="eyebrow">${value.domain==='movie'?'MOVIE ENGINE':'TELEVISION ENGINE'}</span><h2>${label}</h2><p class="muted">${disks.length} mounted path${disks.length===1?'':'s'} reported</p></div>${badge(healthy?'Healthy':'Low space',healthy?'green':'warm')}</div><div class="storage-summary"><div><strong>${Math.round(free/1073741824)} GB</strong><small>free of ${Math.round(total/1073741824)} GB</small></div><div><strong>${Math.round(used/1073741824)} GB</strong><small>used · ${100-freePercent}%</small></div></div><div class="storage-meter" aria-label="${freePercent}% free"><span style="width:${100-freePercent}%"></span></div><div class="status-paths">${disks.map(disk=>{const pathFree=Number(disk.freeSpace||0),pathTotal=Number(disk.totalSpace||0),pathHealthy=pathFree>10737418240;return`<div class="data-row"><span><strong>${esc(disk.path)}</strong><small>${Math.round(pathFree/1073741824)} GB free of ${Math.round(pathTotal/1073741824)} GB</small></span><span class="status-path-state ${pathHealthy?'healthy':'warning'}">${pathHealthy?'Available':'Low space'}</span></div>`;}).join('')||'<p class="muted">No storage paths reported.</p>'}</div></section>`;}).join('')}</div>`;}
function backupSections(items){const size=value=>value<1048576?`${Math.max(1,Math.round(value/1024))} KB`:`${(value/1048576).toFixed(1)} MB`;return`<div class="notice backup-retention-notice"><strong>Download backups before uninstalling.</strong><p>Backups normally remain when only the application container is removed. Deleting Docker volumes or Unraid appdata permanently removes them, so download copies before a complete uninstall.</p></div><div class="backup-domain-list">${[['movie','Movies'],['tv','Television']].map(([domain,label])=>{const backups=items.filter(item=>item.domain===domain);return`<section class="system-domain-section"><div class="panel-heading"><div><span class="eyebrow">${domain==='movie'?'MOVIE ENGINE':'TELEVISION ENGINE'}</span><h2>${label} backups</h2></div><div class="backup-heading-actions"><input class="backup-upload-input" data-domain="${domain}" data-label="${label}" type="file" accept=".zip,.db,.xml" hidden><button class="secondary upload-backup" data-domain="${domain}">Upload & restore</button><span class="badge">${backups.length}</span></div></div>${backups.map(item=>`<div class="data-row backup-row"><span><strong>${label} configuration backup</strong><small>${esc(when(item.time))} · ${esc(item.type||'manual')} · ${size(Number(item.size||0))}</small></span><div class="backup-row-actions"><a class="secondary button-link" href="/api/system/backups/${domain}/${item.id}/download">Download</a><button class="secondary restore-backup" data-domain="${domain}" data-id="${item.id}" data-label="${label}">Restore</button></div></div>`).join('')||'<p class="muted">No backups available.</p>'}</section>`;}).join('')}</div>`;}
function eventSections(items){return`<div class="event-toolbar"><label>Level<select id="event-level"><option value="all">All levels</option><option value="error">Errors</option><option value="warning">Warnings</option><option value="info">Information</option></select></label><label>Find events<input id="event-query" type="search" placeholder="Search messages"></label></div><div class="event-domain-list">${[['movie','Movies'],['tv','Television']].map(([domain,label])=>{const events=items.filter(item=>item.domain===domain);return`<section class="system-domain-section event-domain"><div class="panel-heading"><div><span class="eyebrow">${domain==='movie'?'MOVIE ENGINE':'TELEVISION ENGINE'}</span><h2>${label} events</h2></div><span class="badge event-visible-count">${events.length}</span></div><div class="event-list">${events.slice(0,200).map(item=>{const level=String(item.level||'info').toLowerCase(),message=item.message||item.exception||'Event';return`<article class="event-row event-${esc(level)}" data-level="${esc(level)}" data-search="${esc(String(message).toLowerCase())}"><div><strong>${esc(message)}</strong><span class="event-level">${esc(level)}</span></div><time>${esc(when(item.time))}</time></article>`;}).join('')||'<p class="muted">No events reported.</p>'}</div></section>`;}).join('')}</div>`;}
function wireEventFilters(host){const level=host.querySelector('#event-level'),query=host.querySelector('#event-query');if(!level||!query)return;const apply=()=>{const needle=query.value.trim().toLowerCase();host.querySelectorAll('.event-domain').forEach(section=>{let visible=0;section.querySelectorAll('.event-row').forEach(row=>{const matchesLevel=level.value==='all'||row.dataset.level.includes(level.value),matchesQuery=!needle||row.dataset.search.includes(needle);row.hidden=!(matchesLevel&&matchesQuery);if(!row.hidden)visible++;});section.querySelector('.event-visible-count').textContent=visible;});};level.onchange=apply;query.oninput=apply;}
async function showSystem(){
  content.innerHTML='<div class="hero"><div><span class="eyebrow">SYSTEM</span><h1>System</h1><p class="lede">Health, storage, scheduled tasks, backups, VynodeArr updates, and events.</p></div><button id="sync-now" class="primary">Synchronize now</button></div><div class="settings-tabs system-tabs"><button data-view="status" class="wanted-tab active">Status</button><button data-view="tasks" class="wanted-tab">Tasks</button><button data-view="backups" class="wanted-tab">Backups</button><button data-view="updates" class="wanted-tab">Updates</button><button data-view="events" class="wanted-tab">Events</button></div><div id="system-content" class="panel skeleton">Loading…</div>';
  async function load(view='status'){
    const host=document.querySelector('#system-content');host.className='panel skeleton';host.textContent='Loading…';
    try{
      const domains=['movie','tv'];
      if(view==='updates'){
        const update=await api('/api/system/application-update');
        host.innerHTML=`<div class="application-update"><div><span class="eyebrow">VYNODEARR APPLICATION</span><h2>Version ${esc(update.installedVersion)}</h2><p class="muted">Update channel: ${esc(update.channel)} · ${esc(update.mechanism)}</p></div>${badge('Installed','green')}</div><div class="notice"><strong>VynodeArr updates</strong><p>${esc(update.message)}</p><a class="secondary button-link" href="${esc(update.repository)}" target="_blank" rel="noreferrer">View VynodeArr releases</a></div>`;
      }else if(view==='status'){
        const values=await Promise.all(domains.map(async domain=>({domain,...await api(`/api/manage/${domain}/diskSpace`)})));
        host.innerHTML=statusSections(values);
      }else{
        const values=await Promise.all(domains.map(async domain=>({domain,...await api(`/api/manage/${domain}/${view}?page=1&pageSize=200&sortKey=time&sortDirection=descending`)}))),items=values.flatMap(value=>(value.result?.records||value.result||[]).map(item=>({...item,domain:value.domain})));
        if(view==='tasks')host.innerHTML=taskSections(items);
        else if(view==='backups')host.innerHTML=`<div class="form-actions backup-actions"><button id="create-backups" class="primary">Create Movies and Television backups</button></div>${backupSections(items)}`;
        else{host.innerHTML=eventSections(items);wireEventFilters(host);}
        host.querySelectorAll('.run-task').forEach(button=>button.addEventListener('click',async()=>{try{await api(`/api/manage/${button.dataset.domain}/commands`,{method:'POST',body:JSON.stringify({name:button.dataset.name})});notify(`${button.dataset.domain==='movie'?'Movie':'Television'} task queued.`);}catch(error){notify(error.message,'error');}}));
        host.querySelectorAll('.restore-backup').forEach(button=>button.addEventListener('click',async()=>{if(!confirm(`Restore this ${button.dataset.label} backup? The engine will restart and its current configuration will be replaced.`))return;button.disabled=true;button.textContent='Restoring…';try{await api(`/api/system/backups/${button.dataset.domain}/${button.dataset.id}/restore`,{method:'POST',body:'{}'});notify(`${button.dataset.label} backup restored successfully.`);await load('backups');}catch(error){button.disabled=false;button.textContent='Restore';notify(error.message,'error');}}));
        host.querySelectorAll('.upload-backup').forEach(button=>button.addEventListener('click',()=>host.querySelector(`.backup-upload-input[data-domain="${button.dataset.domain}"]`).click()));
        host.querySelectorAll('.backup-upload-input').forEach(input=>input.addEventListener('change',async()=>{const file=input.files[0];if(!file)return;if(!confirm(`Upload and restore ${input.dataset.label} from ${file.name}? The engine will restart and its current configuration will be replaced.`)){input.value='';return;}const form=new FormData();form.append('file',file);try{notify(`Uploading ${input.dataset.label} backup…`,'info');await api(`/api/system/backups/${input.dataset.domain}/upload`,{method:'POST',body:form});notify(`${input.dataset.label} backup uploaded and restored successfully.`);await load('backups');}catch(error){notify(error.message,'error');}finally{input.value='';}}));
        document.querySelector('#create-backups')?.addEventListener('click',async()=>{try{await Promise.all(domains.map(domain=>api(`/api/manage/${domain}/commands`,{method:'POST',body:JSON.stringify({name:'Backup'})})));notify('Backup commands queued.');}catch(error){notify(error.message,'error');}});
      }
      host.className='panel';
    }catch(error){host.className='panel';host.innerHTML=`<div class="error-state"><p>${esc(error.message)}</p></div>`;}
  }
  document.querySelector('#sync-now').addEventListener('click',async()=>{try{await api('/api/system/sync',{method:'POST'});notify('Synchronization completed.');load('status');}catch(error){notify(error.message,'error');}});
  content.querySelectorAll('.system-tabs button').forEach(button=>button.addEventListener('click',()=>{content.querySelectorAll('.system-tabs button').forEach(x=>x.classList.toggle('active',x===button));load(button.dataset.view);}));
  await load();
}
async function showManagement(){
  if(state.user.role!=='administrator'){content.innerHTML='<div class="empty error-state"><h2>Administrator access required</h2><p>Media management changes are restricted to administrators.</p></div>';return;}
  content.innerHTML=`<div class="hero"><div><span class="eyebrow">CONTROL CENTER</span><h1>Service Settings</h1><p class="lede">Configure acquisition, automation, quality, storage, integrations, and advanced service behavior.</p></div></div><div class="management-toolbar"><label>Library<select id="manage-domain"><option value="movie">Movies</option><option value="tv">Television</option></select></label><label>Setting or resource<select id="manage-resource"></select></label><button id="manage-load" class="secondary">Load</button><button id="manage-create" class="primary">Add</button></div><div class="management-layout"><section class="panel"><div class="panel-heading"><h2>Configured records</h2><span id="manage-count" class="badge">0</span></div><div id="manage-records" class="management-records"><p class="muted">Choose a setting to begin.</p></div></section><section class="panel editor-panel"><h2>Advanced editor</h2><p class="muted">Choose a record to review every supported field. Provider additions use a guided form; advanced JSON remains available for complete field parity.</p><label>Resource ID<input id="manage-id" placeholder="Assigned automatically when creating"></label><label>Fields<textarea id="manage-json" spellcheck="false" rows="18">{}</textarea></label><div class="form-actions"><button id="manage-delete" class="danger">Delete</button><button id="manage-save" class="primary">Save changes</button></div></section></div><section class="panel"><h2>Change audit</h2><div id="manage-audit"></div></section><dialog id="provider-dialog"></dialog>`;
  content.querySelector('.hero').insertAdjacentHTML('afterend',serviceTabs('advanced'));
  const domain=document.querySelector('#manage-domain'),resource=document.querySelector('#manage-resource'),records=document.querySelector('#manage-records'),editor=document.querySelector('#manage-json'),id=document.querySelector('#manage-id');let selectedRecord=null;
  async function catalog(){const value=await api(`/api/manage/${domain.value}`);resource.innerHTML=value.resources.map((item)=>`<option value="${esc(item.key)}">${esc(item.key.replace(/([A-Z])/g,' $1'))}</option>`).join('');if(!value.available){records.innerHTML='<div class="empty"><h2>Connect production engines</h2><p>This control center becomes active when private movie and television engines are configured.</p></div>';document.querySelector('#manage-count').textContent='0';await loadAudit();return;}await load();}
  async function load(){records.innerHTML='<p class="muted">Loading…</p>';selectedRecord=null;try{const value=await api(`/api/manage/${domain.value}/${resource.value}`),items=Array.isArray(value.result)?value.result:Array.isArray(value.result?.records)?value.result.records:value.result?[value.result]:[];document.querySelector('#manage-count').textContent=items.length;records.innerHTML=items.length?items.slice(0,500).map((item,index)=>`<button class="management-record" data-index="${index}"><strong>${esc(item.title||item.name||item.label||`Record ${item.id??index+1}`)}</strong><small>ID ${esc(item.id??'configuration')}</small></button>`).join(''):'<p class="muted">No records returned.</p>';records.querySelectorAll('button').forEach((button)=>button.addEventListener('click',()=>{const item=items[Number(button.dataset.index)];selectedRecord=structuredClone(item);id.value=item.id??'';editor.value=JSON.stringify(providerPresentation(item,domain.value),null,2);}));}catch(error){records.innerHTML=`<div class="error-state"><p>${esc(error.message)}</p></div>`;}await loadAudit();}
  async function loadAudit(){try{const{items}=await api('/api/manage/audit');document.querySelector('#manage-audit').innerHTML=items.slice(0,10).map((item)=>`<div class="data-row"><span><strong>${esc(item.method)} ${esc(item.domain)} ${esc(item.resource)}</strong><small>${esc(item.username)}</small></span><span>${esc(when(item.timestamp))}</span></div>`).join('')||'<p class="muted">No changes recorded.</p>';}catch{}}
  async function change(method){let payload;try{payload=JSON.parse(editor.value||'{}');if(selectedRecord&&method==='PUT')payload=mergeProviderPayload(selectedRecord,payload);}catch{notify('The editor must contain valid JSON.','error');return;}if((method==='PUT'||method==='DELETE')&&!id.value){notify('Select a record with an ID first.','error');return;}if(method==='DELETE'&&!confirm('Delete this record from the connected media service?'))return;try{await api(`/api/manage/${domain.value}/${resource.value}${id.value?`/${encodeURIComponent(id.value)}`:''}`,{method,body:method==='DELETE'?undefined:JSON.stringify(payload)});notify(method==='POST'?'Record created.':method==='PUT'?'Changes saved.':'Record deleted.');editor.value='{}';id.value='';selectedRecord=null;await load();}catch(error){notify(error.message,'error');}}
  async function createRecord(){id.value='';const schemas={indexers:'indexerSchemas',downloadClients:'downloadClientSchemas',notifications:'notificationSchemas',importLists:'importListSchemas',metadata:'metadataSchemas'},schemaResource=schemas[resource.value];if(!schemaResource){editor.value='{}';editor.focus();return;}try{const{result:definitions}=await api(`/api/manage/${domain.value}/${schemaResource}`),dialog=document.querySelector('#provider-dialog');dialog.innerHTML=`<form id="provider-form"><h2>Add ${esc(resource.value.replace(/([A-Z])/g,' $1'))}</h2><label>Provider<select id="provider-kind">${definitions.map((definition,index)=>`<option value="${index}">${esc(definition.name||definition.implementationName||definition.implementation)}</option>`).join('')}</select></label><div id="provider-fields"></div><div class="form-actions"><button type="button" class="secondary close-provider">Cancel</button><button class="primary" type="submit">Review configuration</button></div></form>`;const kind=dialog.querySelector('#provider-kind'),fields=dialog.querySelector('#provider-fields');function render(){const definition=definitions[Number(kind.value)];fields.innerHTML=`<label>Name<input name="providerName" value="${esc(definition.name||'')}"></label>${(definition.fields||[]).filter(field=>!field.hidden||field.advanced).map(field=>`<label>${esc(field.label||field.name)}${field.helpText?`<small>${esc(field.helpText)}</small>`:''}${field.type==='boolean'?`<input name="field_${esc(field.name)}" type="checkbox"${field.value?' checked':''}>`:`<input name="field_${esc(field.name)}" value="${esc(field.value??'')}"${field.privacy==='password'?' type="password"':''}>`}</label>`).join('')}`;}kind.addEventListener('change',render);render();dialog.querySelector('.close-provider').addEventListener('click',()=>dialog.close());dialog.querySelector('form').addEventListener('submit',event=>{event.preventDefault();const definition=structuredClone(definitions[Number(kind.value)]),values=formValue(event.currentTarget);definition.name=values.providerName;definition.fields=(definition.fields||[]).map(field=>({...field,value:field.type==='boolean'?values[`field_${field.name}`]==='on':values[`field_${field.name}`]??field.value}));editor.value=JSON.stringify(definition,null,2);dialog.close();editor.focus();});dialog.showModal();}catch(error){notify(error.message,'error');}}
  domain.addEventListener('change',catalog);resource.addEventListener('change',load);document.querySelector('#manage-load').addEventListener('click',load);document.querySelector('#manage-create').addEventListener('click',createRecord);document.querySelector('#manage-save').addEventListener('click',()=>change(id.value?'PUT':'POST'));document.querySelector('#manage-delete').addEventListener('click',()=>change('DELETE'));await catalog();
}
async function route(){if(shell.hidden)return;const raw=location.hash.slice(1)||'dashboard',parts=raw.split('/'),key=parts[0];nav.forEach((link)=>link.classList.toggle('active',link.hash.startsWith(`#${key}`)||key==='settings'&&link.hash==='#settings'));document.body.classList.remove('nav-open');if(key==='engine-setup')return showEngineSetup();if(key==='movies'||key==='tv')return showMedia(key);if(key==='add')return showAddMedia();if(key==='wanted')return showWanted();if(key==='movie'||key==='series')return showDetail(key,parts[1]);if(key==='queue')return showQueue();if(key==='history')return showOperational('History','/api/activity/history');if(key==='calendar')return showCalendar();if(key==='health')return showHealth();if(key==='service')return showServiceSettings(parts[1]);if(key==='management')return showManagement();if(key==='settings')return showSettings(parts[1]);if(key==='system')return showSystem();return showDashboard();}
addEventListener('hashchange',route);bootstrap();
